import React, { useState } from 'react';
import api from '../../api'; // Default import for the axios instance

const FoodLogger = ({ onFoodLogged }) => {
  const [foodName, setFoodName] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const onSubmit = async (e) => {
    e.preventDefault();
    setError('');
    if (!foodName) {
      setError('Please enter a food name.');
      return;
    }
    setLoading(true);
    try {
      // Use the imported api object to make a POST request
      const res = await api.post('/food/log', { name: foodName });
      if (onFoodLogged) {
        onFoodLogged(res.data);
      }
      setFoodName('');
    } catch (err) {
      setError('Could not find nutrition data for this food. Please try another.');
      console.error('Error logging food:', err);
    } finally {
      setLoading(false);
    }
  };

  return (
    <form onSubmit={onSubmit}>
      <div className="flex flex-col sm:flex-row gap-4">
        <input
          type="text"
          name="foodName"
          value={foodName}
          onChange={(e) => setFoodName(e.target.value)}
          placeholder="e.g., 1 cup cooked dal"
          className="flex-grow p-3 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-green-500"
        />
        <button
          type="submit"
          disabled={loading}
          className="bg-green-500 text-white px-6 py-3 rounded-md hover:bg-green-600 focus:outline-none focus:ring-2 focus:ring-green-500 focus:ring-opacity-50 disabled:bg-gray-400"
        >
          {loading ? 'Logging...' : 'Log Food'}
        </button>
      </div>
      {error && <p className="text-red-500 text-sm mt-2">{error}</p>}
    </form>
  );
};

export default FoodLogger;
